<?php require dirname(__DIR__).'/includes/pawn_bootstrap.php';pawn_require_csrf();$id=(int)($_POST['pawn_entry_id']??0);$date=(string)($_POST['payment_date']??'');$principal=(float)($_POST['principal_amount']??0);$interest=(float)($_POST['interest_amount']??0);$penalty=(float)($_POST['penalty_amount']??0);$total=$principal+$interest+$penalty;$method=(int)($_POST['payment_method_id']??0);$close=!empty($_POST['is_closure']);if($id<=0||$principal<0||$total<=0)pawn_json(false,'Invalid payment details.');$conn->begin_transaction();try{$st=$conn->prepare("SELECT balance_principal,status FROM pawn_entries WHERE id=? AND business_id=? AND branch_id=? FOR UPDATE");$st->bind_param('iii',$id,$businessId,$branchId);$st->execute();$p=$st->get_result()->fetch_assoc();$st->close();if(!$p||!in_array($p['status'],['Active','Partially Paid'],true))throw new Exception('Pawn is not active.');if($principal>(float)$p['balance_principal']+0.001)throw new Exception('Principal exceeds outstanding balance.');$receipt=pawn_next_no($conn,$businessId,$branchId,'PawnPayment','PAY');$isClosure=($close&&abs((float)$p['balance_principal']-$principal)<0.01)?1:0;$st=$conn->prepare('INSERT INTO pawn_payments(business_id,branch_id,pawn_entry_id,receipt_no,payment_date,principal_amount,interest_amount,penalty_amount,total_amount,payment_method_id,is_closure,created_by) VALUES(?,?,?,?,?,?,?,?,?,?,?,?)');$methodVal=$method?:null;$st->bind_param('iiissddddiii',$businessId,$branchId,$id,$receipt,$date,$principal,$interest,$penalty,$total,$methodVal,$isClosure,$userId);$st->execute();$st->close();$new=max(0,(float)$p['balance_principal']-$principal);$status=$new<=0.009?'Closed':($principal>0?'Partially Paid':$p['status']);$st=$conn->prepare('UPDATE pawn_entries SET total_principal_paid=total_principal_paid+?,total_interest_collected=total_interest_collected+?,balance_principal=?,status=? WHERE id=? AND business_id=?');$st->bind_param('dddsii',$principal,$interest,$new,$status,$id,$businessId);$st->execute();$st->close();$conn->commit();pawn_json(true,'Payment saved successfully.');}catch(Throwable $e){$conn->rollback();pawn_json(false,$e->getMessage());}
